return items.map(i => {
  function cleanText(str) {
    if (!str) return '';
    let out = str.replace(/[\r\n]+/g, ' ');
    out = out.replace(/\s{2,}/g, ' ');
    out = out.replace(/'/g, "''");
    out = out.trim();
    return out;
  }

  return {
    json: {
      post_id: cleanText(i.json["post-id"]),
      solicitacao: cleanText(i.json["solicitacao"]),
      post_description: cleanText(i.json["post-description"]),
      image_prompt: cleanText(i.json["image-prompt"])
    }
  };
});

